// Re-authenticate to nemlig.com and add all approved items to basket.
const axios = require('axios');
const crypto = require('crypto');

const BASE_URL = 'https://www.nemlig.com';
const username = 'chemay.shola@gmail.com';
const password = '@FaggotNigger69!';

const items = $input.first().json.body.items || [];
if (items.length === 0) {
  throw new Error('No items to add');
}

const commonHeaders = {
  'Accept': 'application/json, text/plain, */*',
  'Content-Type': 'application/json',
  'User-Agent': 'Mozilla/5.0 (X11; Linux x86_64) AppleWebKit/537.36 (KHTML, like Gecko) Chrome/136.0.0.0 Safari/537.36',
  'Device-Size': 'desktop',
  'Platform': 'web',
  'Version': '11.201.0',
};

let cookies = {};

function parseCookies(resp) {
  const setCookies = resp.headers['set-cookie'] || [];
  for (const c of setCookies) {
    const parts = c.split(';')[0].split('=');
    const name = parts[0].trim();
    const value = parts.slice(1).join('=').trim();
    cookies[name] = value;
  }
}

function cookieHeader() {
  return Object.entries(cookies).map(([k, v]) => `${k}=${v}`).join('; ');
}

async function req(method, url, data, extraHeaders) {
  const headers = {
    ...commonHeaders,
    'X-Correlation-Id': crypto.randomUUID(),
    'Cookie': cookieHeader(),
    ...extraHeaders
  };
  const resp = await axios({ method, url, data, headers, validateStatus: () => true });
  parseCookies(resp);
  if (resp.status >= 400) {
    throw new Error(`${method.toUpperCase()} ${url} returned ${resp.status}: ${JSON.stringify(resp.data).substring(0, 300)}`);
  }
  return resp;
}

const xsrfResp = await req('get', `${BASE_URL}/webapi/AntiForgery`);
const xsrfToken = xsrfResp.data.Value;

const tokenResp = await req('get', `${BASE_URL}/webapi/Token`);
const bearerToken = tokenResp.data.access_token;

const loginResp = await req('post', `${BASE_URL}/webapi/login`, {
  Username: username,
  Password: password,
  CheckForExistingProducts: true,
  DoMerge: true,
  AppInstalled: false,
  SaveExistingBasket: false
}, {
  'X-XSRF-TOKEN': xsrfToken,
  'Authorization': `Bearer ${bearerToken}`,
  'Referer': `${BASE_URL}/login?returnUrl=%2F`
});

if (!loginResp.data.RedirectUrl) {
  throw new Error('Login failed: ' + JSON.stringify(loginResp.data).substring(0, 300));
}

const freshTokenResp = await req('get', `${BASE_URL}/webapi/Token`);
const freshBearer = freshTokenResp.data.access_token;

const freshXsrfResp = await req('get', `${BASE_URL}/webapi/AntiForgery`);
const freshXsrf = freshXsrfResp.data.Value;

const results = [];

for (const item of items) {
  try {
    if (results.length > 0) {
      await new Promise(resolve => setTimeout(resolve, 1000));
    }

    await req('post', `${BASE_URL}/webapi/basket/AddToBasket`, {
      ProductId: String(item.productId),
      quantity: item.quantity || 1,
      AffectPartialQuantity: false,
      disableQuantityValidation: false
    }, {
      'X-XSRF-TOKEN': freshXsrf,
      'Authorization': `Bearer ${freshBearer}`,
      'Referer': `${BASE_URL}/`
    });

    results.push({ productId: item.productId, name: item.name, success: true });
  } catch (e) {
    results.push({ productId: item.productId, name: item.name, success: false, error: e.message });
  }
}

const added = results.filter(r => r.success).length;
const failed = results.filter(r => !r.success).length;

return [{
  json: { results, added, failed, totalItems: items.length }
}];
